labels.example:
SELECT category, COUNT(*) AS total, AVG(price) AS avg_price
FROM products
GROUP BY category;

SELECT c.name, o.total
FROM customers c
JOIN orders o ON o.customer_id = c.id;

SELECT name, total_sales
FROM summary
ORDER BY total_sales DESC;

